using Microsoft.EntityFrameworkCore;using MundoVs.Core.Entities;using MundoVs.Core.Interfaces;using MundoVs.Infrastructure.Data;namespace MundoVs.Infrastructure.Repositories;public class AppConfigRepository : IAppConfigRepository{    private readonly IDbContextFactory<CrmDbContext> _contextFactory;    private readonly IEmpresaContext _empresaContext;    public AppConfigRepository(IDbContextFactory<CrmDbContext> contextFactory, IEmpresaContext empresaContext)    {        _contextFactory = contextFactory;        _empresaContext = empresaContext;    }    public async Task<string?> GetValueAsync(string clave)    {        await using var context = await _contextFactory.CreateDbContextAsync();        var config = await context.AppConfigs            .AsNoTracking()            .FirstOrDefaultAsync(c => c.Clave == clave);        return config?.Valor;    }    public async Task SetValueAsync(string clave, string valor, string? descripcion = null)    {        await using var context = await _contextFactory.CreateDbContextAsync();        var config = await context.AppConfigs.FirstOrDefaultAsync(c => c.Clave == clave);        if (config != null)        {            config.Valor = valor;            config.UpdatedAt = DateTime.UtcNow;            if (descripcion != null) config.Descripcion = descripcion;        }        else        {            if (_empresaContext.EmpresaId == Guid.Empty)            {                throw new InvalidOperationException("No hay empresa activa para guardar configuración.");            }            config = new AppConfig            {                EmpresaId = _empresaContext.EmpresaId,                Clave = clave,                Valor = valor,                Descripcion = descripcion            };            await context.AppConfigs.AddAsync(config);        }        await context.SaveChangesAsync();    }    public async Task<IEnumerable<AppConfig>> GetAllAsync()    {        await using var context = await _contextFactory.CreateDbContextAsync();        return await context.AppConfigs            .AsNoTracking()            .OrderBy(c => c.Clave)            .ToListAsync();    }    public async Task<string> GetNextCodeAsync(string prefijo, string claveConsecutivo)    {        await using var context = await _contextFactory.CreateDbContextAsync();        var config = await context.AppConfigs.FirstOrDefaultAsync(c => c.Clave == claveConsecutivo);        int siguiente = 1;        if (config != null)        {            siguiente = int.Parse(config.Valor) + 1;            config.Valor = siguiente.ToString();            config.UpdatedAt = DateTime.UtcNow;        }        else        {            if (_empresaContext.EmpresaId == Guid.Empty)            {                throw new InvalidOperationException("No hay empresa activa para guardar configuración.");            }            config = new AppConfig            {                EmpresaId = _empresaContext.EmpresaId,                Clave = claveConsecutivo,                Valor = siguiente.ToString(),                Descripcion = $"Consecutivo para {prefijo}"            };            await context.AppConfigs.AddAsync(config);        }        await context.SaveChangesAsync();        return $"{prefijo}{siguiente:D3}";    }}